<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class ZonesSeeder extends Seeder
{
    public function run(): void
    {
        // Uses raw SQL statements to handle PostGIS geography type casting
        foreach ($this->getZones() as $zone) {
            $existing = DB::table('zones')->where('name', $zone['name'])->first();
            if ($existing) {
                continue;
            }

            DB::statement(
                "INSERT INTO zones (name, description, zone_base_id, geometry, created_at, updated_at, deleted_at)
                 VALUES (?, ?, ?, ST_GeographyFromText(?), ?, ?, ?)",
                [
                    $zone['name'],
                    $zone['description'],
                    $zone['zone_base_id'],
                    $zone['geometry'],
                    $zone['created_at'],
                    $zone['updated_at'],
                    $zone['deleted_at'],
                ]
            );
        }
    }

